/**
 * TODO: Add JSDoc
 */
export const PrimarySplitButton = ({
  children,
  isHighlighted = false
}) => {
  const {
    PrimaryAction,
    SecondaryAction
  } = getActions(children);
  return jsx("div", {
    css: [buttonBaseStyles, isHighlighted && buttonHighlightedStyles]
  }, jsx(SplitButtonContainer, null, jsx(SplitButtonContext.Provider, {
    value: {
      appearance: 'navigation',
      isHighlighted
    }
  }, PrimaryAction, jsx(Divider, {
    appearance: "navigation",
    spacing: "default",
    isDisabled: false
  }), SecondaryAction)));
};